function initSkills(){
	user["activity_window"] = "skills";
	chooseMenu(idArray[4]);
	var progress = 100;
	var text = "<div class=\"linebox\">"+
			"<div id=\"level\" class=\"mini_info\">⭐️"+formatNumber(user['stars'])+"</div>"+
			"<div id=\"coins\" class=\"mini_info\">💠"+formatNumber(user['coins'])+"</div>"+
			"<div id=\"diamonds\" class=\"mini_info\">💎"+formatNumber(user['diamonds'])+"</div>"+
		"</div>";

		if (user["train_skill"] !== "") {

			text += "<div class=\"linebox\">";
				text += "<div id=\"timer\" class=\"mini_info\"><center>"+translate[user["train_skill"]+"_name"][user["lang"]]+" ⏱"+formatSeconds(user.getTrainTimeLeft())+"</center></div>";
			text += "</div>";
		}

		text += "<div class=\"linebox\">";
			text += "<div class=\"shop_container\">";

			for (const [key, value] of Object.entries(User.skills)) {
				if (key === "user") {
					continue;
				}

				if (user["train_skill"] === key) {
					progress = 100 - user.getTrainProgress() * 100;
				} else {
					progress = 100;
				}

				text += "<div class=\"shop_card\" onclick=\"openCard('"+key+"');\">" +
				"<div class=\"shop_desc\"><img class=\"card-img\" src=\""+skill_icons[key]+"\"><br><b>"+translate[`${key}_name`][user["lang"]]+"</b><br></div>" +
				"<div class=\"shop_container\"><div class=\"shop_desc\">"+translate["skill_level"][user["lang"]]+" "+user.getSkill(key)+"</div>" +
				"<div class=\"shop_desc\">⭐️"+formatNumber(value['cost'])+"</div></div>"+
				"<div class=\"progress-bar\"><div class=\"progress-fill\" id=\""+key+"\" style=\"background-color: #333; width: "+progress+"%;\"></div></div>" +
				"</div>";
				
			}

			text += "</div>"+
		"</div>"+
		"<div class=\"linebox\">"+
			"<div id=\"ads\" class=\"ads\">Ads</div>"+
		"</div>";
	document.getElementById('main').innerHTML = text;
	document.getElementById("ads").innerHTML = ad.getLineAd();
}

function initExchange(){
	chooseMenu(idArray[5]);
	user["stars"] += 1000;
	user["coins"] += 50;
	user["diamonds"] += 3;
	updateView();
}

