//General code
try {
	let tg = window.Telegram.WebApp;

	var userId = 1;
	var userIsBot = false;
	var userName = "Demo";
	var userLang = "ru";

	try {
		userId = tg.initDataUnsafe.user.id;
		userIsBot = tg.initDataUnsafe.user.isBot;
		userName = `${tg.initDataUnsafe.user.first_name} ${tg.initDataUnsafe.user.last_name}`;
		userLang = tg.initDataUnsafe.user.language_code === "ru" ? "ru": "en";
	}
	catch {
		userId = 1;
		userIsBot = false;
		userName = "Demo";
		userLang = "ru";

		const text = "";
	}

	if (userIsBot == true) {
		throw new TypeError("User is Bot. Please, use Telegram as Human.", e);
	}

	var block = new Block();
	var send_block = null;

	var ad = new ADs();

	var user = new User();

	if (userCookie != null) {
		user.parse(userCookie);
	}
	
	user["id"] = userId;
	user["name"] = userName;
	user["lang"] = userLang;

	initMenu();
	initMining();

	setInterval(function(){

		const new_activity_time = (new Date()).getTime();

		var delta = Math.max(0, Math.min(3*60*60*1000, (new_activity_time - user["activity_time"])));

		// update VIP, rewards, NEW DAY
		if (new_activity_time - user["activity_time"] > 86400000) {
			if (user["start_today"]-user["start_yesterday"] == 86400000) {
				user["activity_days"] += 1;
			} else {
				user["activity_days"] = 1;
			}
			user.setBuff("skill_vip_1", (new_activity_time + 15 * 60 * 1000));
			user["boosts"] = 0;
			user.resetRewards();
			user.resetCombo();
			user["start_today"] = new_activity_time - new_activity_time % 86400000;
			user["start_yesterday"] = user["start_today"] - 86400000;
			createCongrat(translate["note_congratulation"][user["lang"]], translate["note_get_vip"][user["lang"]]);
		}

		user["activity_time"] = new_activity_time;

		const combo = user.getCombo();

		//ADs
		const ads = ad.getNewLineAd();
		if (ads !== null) {
			document.getElementById("ads").innerHTML = ads;
		}

		
		





		//Train
		if (user["train_skill"] !== "") {
			user["train_time"] += delta;
			if (user.getTrainProgress() > 1) {
				const skill = user.getSkill(user["train_skill"]);
				user.levelUpSkill(user["train_skill"]);
				user["train_skill"] = "";
				user["train_time"] = 0;
				if(user["activity_window"] == "skills") {
					document.getElementById("timer").remove();
				}
				updateView();
			}
			
			if(user["activity_window"] == "skills") {
				const progress = 100 - user.getTrainProgress() * 100;
				document.getElementById(user["train_skill"]).style.width = progress + '%';
				document.getElementById("timer").innerHTML = "<center>"+translate[user["train_skill"]+"_name"][user["lang"]]+" ⏱"+formatSeconds(user.getTrainTimeLeft())+"</center>";
			}
		}


		delta = Math.max(0, Math.min(15*60*1000, delta));

		//console.log('delta='+delta);
		if(user.check_ads() == true){
			createCongrat("Поздравляем!", "Вы заработали кристалл", "ads");
		}
		//check Energy & Buffs
		user['energy'] += Math.round(user.getRecoverySpeed() * delta/1000);
		user['energy'] = user['energy'] > user.getFullEnergy() ? user.getFullEnergy() : user['energy'];
		if (user['activity_window'] == "main") {
			document.getElementById('energy').innerHTML = "🔋 "+user['energy']+" / "+user.getFullEnergy();
			
			var num_active_buffs = 0;
			var active_buffs = {};
			for (const [key, value] of Object.entries(user.getBuffData())) {
				if (value > (new Date()).getTime()) {
					num_active_buffs += 1;
					active_buffs[key] = value;
				}
			}

			if (num_active_buffs > 0) {
				var text = "";
				for(const [key, value] of Object.entries(active_buffs)) {

					text += "<div class=\"minicard\"><img class=\"minicard-img\" src=\""+buff_icons[key]+"\"><br>"+formatSeconds(value - (new Date()).getTime())+"</div>";
				}
				document.getElementById('buffs').innerHTML = text;
				if(user.getCombo()) {
					const combo = document.querySelectorAll('.minicard');
					combo.forEach(div => {
						div.classList.add('combo');
					});
				}
			} else {
				document.getElementById('buffs').innerHTML = "";
			}
		}


		setCookie('user',user.dump(),3650);
		//document.getElementById("ads").innerText = user.dump();
	}, 1000);
}
catch (e) {
	console.log(e.name);
	console.log(e.message);
	document.getElementById("main").innerHTML = "Please use Telegram.";
}